fun main() {
    // ---- Challenge: Null safe operations ----
    // This is the complete working solution

    // Challenge 1: Safe length
    fun safeLength(text: String?): Int = text?.length ?: 0
    println("safeLength(null): ${safeLength(null)}")
    println("safeLength(\"Hello\"): ${safeLength("Hello")}")

    // Challenge 2: Default greeting
    fun greetUser(name: String?): String = "Hello, ${name ?: "Guest"}!"
    println("greetUser(null): ${greetUser(null)}")
    println("greetUser(\"Alice\"): ${greetUser("Alice")}")

    // Challenge 3: Safe chain
    data class Address(val city: String)
    data class User(val name: String, val address: Address?)

    fun getCityOrUnknown(user: User?): String = user?.address?.city ?: "Unknown"

    val user1 = User("Alice", Address("Tokyo"))
    val user2 = User("Bob", null)

    println("User1 city: ${getCityOrUnknown(user1)}")
    println("User2 city: ${getCityOrUnknown(user2)}")
    println("Null user city: ${getCityOrUnknown(null)}")

    // Challenge 4: Safe process
    fun processUser(user: User?): String {
        user?.let {
            return "Processing ${it.name} from ${it.address?.city ?: "unknown city"}"
        }
        return "No user to process"
    }

    println("processUser(User1): ${processUser(user1)}")
    println("processUser(User2): ${processUser(user2)}")
    println("processUser(null): ${processUser(null)}")

    // Challenge 5: Not-null assertion (use carefully)
    val definitelyNotNull: String? = "I am not null"
    val length = definitelyNotNull!!.length
    println("Definitely not null length: $length")

    // ---- Bonus: Comprehensive null safety ----
    data class Person(val name: String?, val email: String?, val age: Int?)

    fun getPersonInfo(person: Person?): String {
        if (person == null) return "No person"
        val name = person.name ?: "Anonymous"
        val email = person.email ?: "no email"
        val age = person.age?.toString() ?: "unknown"
        return "Name: $name, Email: $email, Age: $age"
    }

    val p1 = Person("Alice", "alice@example.com", 25)
    val p2 = Person(null, null, null)
    println("Person1: ${getPersonInfo(p1)}")
    println("Person2: ${getPersonInfo(p2)}")
    println("Null person: ${getPersonInfo(null)}")
}

